#[derive(Clone, Debug)]
struct FakeBackend {
    state: Arc<Mutex<FakeBackendState>>,
}

#[derive(Debug)]
struct FakeBackendState {
    replies: VecDeque<String>,
    command_outputs: VecDeque<String>,
    launches: Vec<AgentLaunch>,
    sends: Vec<(AgentId, String)>,
    commands: Vec<(AgentId, String, String)>,
}

#[derive(Clone, Debug)]
struct ConcurrentBackend;

impl FakeBackend {
    fn new<const N: usize>(replies: [&str; N]) -> Self {
        Self {
            state: Arc::new(Mutex::new(FakeBackendState {
                replies: replies.into_iter().map(String::from).collect(),
                command_outputs: VecDeque::new(),
                launches: Vec::new(),
                sends: Vec::new(),
                commands: Vec::new(),
            })),
        }
    }

    fn with_command_outputs<const N: usize>(self, outputs: [&str; N]) -> Self {
        self.state.lock().unwrap().command_outputs =
            outputs.into_iter().map(String::from).collect();
        self
    }

    fn launches(&self) -> Vec<AgentLaunch> {
        self.state.lock().unwrap().launches.clone()
    }

    fn sends(&self) -> Vec<(AgentId, String)> {
        self.state.lock().unwrap().sends.clone()
    }

    fn commands(&self) -> Vec<(AgentId, String, String)> {
        self.state.lock().unwrap().commands.clone()
    }

    fn next_reply(&self) -> String {
        self.state
            .lock()
            .unwrap()
            .replies
            .pop_front()
            .expect("missing fake reply")
    }

    fn next_command_output(&self) -> String {
        self.state
            .lock()
            .unwrap()
            .command_outputs
            .pop_front()
            .expect("missing fake command output")
    }

    fn title_reply(&self, prompt: &str) -> String {
        fake_title_from_title_prompt(prompt)
    }
}

impl AgentBackend for FakeBackend {
    fn launch(&mut self, request: AgentLaunch) -> Result<AgentSession, AgentError> {
        self.state.lock().unwrap().launches.push(request.clone());
        let mut session = AgentSession::new(request);
        let reply = if session.id.as_str().starts_with("title-") {
            self.title_reply(&session.messages[0].text)
        } else {
            self.next_reply()
        };
        session.push_message(MessageRole::Agent, reply);
        Ok(session)
    }

    fn send(&mut self, agent_id: &AgentId, prompt: &str) -> Result<ChatMessage, AgentError> {
        self.state
            .lock()
            .unwrap()
            .sends
            .push((agent_id.clone(), prompt.to_string()));
        Ok(ChatMessage::new(MessageRole::Agent, self.next_reply()))
    }

    fn command(
        &mut self,
        agent_id: &AgentId,
        command: &str,
        arguments: &str,
    ) -> Result<ChatMessage, AgentError> {
        self.state.lock().unwrap().commands.push((
            agent_id.clone(),
            command.to_string(),
            arguments.to_string(),
        ));
        Ok(ChatMessage::new(
            MessageRole::Agent,
            self.next_command_output(),
        ))
    }
}

